import React from "react";

function Form({ data, setData }) {
  const updateField = (e) => {
    setData({
      ...data,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div style={{ width: "50%" }}>
      <h2>Form</h2>

      <input name="name" placeholder="Name" value={data.name} onChange={updateField} />
      <br /><br />

      <input name="email" placeholder="Email" value={data.email} onChange={updateField} />
      <br /><br />

      <input name="phone" placeholder="Phone" value={data.phone} onChange={updateField} />
      <br /><br />

      <textarea name="skills" placeholder="Skills" value={data.skills} onChange={updateField} />

      <h3>Education</h3>
      {data.education.map((item, i) => (
        <div key={i}>
          <input
            placeholder="College"
            value={item.college}
            onChange={(e) => {
              const list = [...data.education];
              list[i].college = e.target.value;
              setData({ ...data, education: list });
            }}
          />
          <input
            placeholder="Degree"
            value={item.degree}
            onChange={(e) => {
              const list = [...data.education];
              list[i].degree = e.target.value;
              setData({ ...data, education: list });
            }}
          />
          <input
            placeholder="Year"
            value={item.year}
            onChange={(e) => {
              const list = [...data.education];
              list[i].year = e.target.value;
              setData({ ...data, education: list });
            }}
          />
          <button onClick={() => {
            const list = data.education.filter((_, idx) => idx !== i);
            setData({ ...data, education: list });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          education: [...data.education, { college: "", degree: "", year: "" }]
        })
      }>Add Education</button>

      <h3>Experience</h3>
      {data.experience.map((item, i) => (
        <div key={i}>
          <input
            placeholder="Company"
            value={item.company}
            onChange={(e) => {
              const list = [...data.experience];
              list[i].company = e.target.value;
              setData({ ...data, experience: list });
            }}
          />
          <input
            placeholder="Role"
            value={item.role}
            onChange={(e) => {
              const list = [...data.experience];
              list[i].role = e.target.value;
              setData({ ...data, experience: list });
            }}
          />
          <input
            placeholder="Year"
            value={item.year}
            onChange={(e) => {
              const list = [...data.experience];
              list[i].year = e.target.value;
              setData({ ...data, experience: list });
            }}
          />
          <button onClick={() => {
            const list = data.experience.filter((_, idx) => idx !== i);
            setData({ ...data, experience: list });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          experience: [...data.experience, { company: "", role: "", year: "" }]
        })
      }>Add Experience</button>

      <h3>Projects</h3>
      {data.projects.map((item, i) => (
        <div key={i}>
          <input
            placeholder="Project Title"
            value={item.title}
            onChange={(e) => {
              const list = [...data.projects];
              list[i].title = e.target.value;
              setData({ ...data, projects: list });
            }}
          />
          <input
            placeholder="Tech Stack"
            value={item.tech}
            onChange={(e) => {
              const list = [...data.projects];
              list[i].tech = e.target.value;
              setData({ ...data, projects: list });
            }}
          />
          <textarea
            placeholder="Description"
            value={item.description}
            onChange={(e) => {
              const list = [...data.projects];
              list[i].description = e.target.value;
              setData({ ...data, projects: list });
            }}
          />
          <button onClick={() => {
            const list = data.projects.filter((_, idx) => idx !== i);
            setData({ ...data, projects: list });
          }}>Remove</button>
          <br /><br />
        </div>
      ))}
      <button onClick={() =>
        setData({
          ...data,
          projects: [...data.projects, { title: "", tech: "", description: "" }]
        })
      }>Add Project</button>
    </div>
  );
}

export default Form;
